.message-input {
    display: flex;
    gap: 0.5rem;
    padding: 0.75rem 1rem;
    border-top: 1px solid #3a3d42;
    background: #2c2f33;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #4a4d52;
