arguments.file_text:
.message-item {
    position: relative;
    padding: 0.5rem 1rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-item:hover {
    background: rgba(255, 255, 255, 0.03);
}

.message-item.highlighted {
    background: rgba(88, 101, 242, 0.08);
    border-left: 3px solid #5865f2;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.125rem;
}

.message-author {
    font-weight: 600;
    font-size: 0.95rem;
    color: #fff;
}

.message-time {
    font-size: 0.75rem;
    color: #72767d;
}

.message-content {
    font-size: 0.9rem;
    color: #dcddde;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-link {
    background: none;
    border: none;
    color: #00aff4;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 0.25rem 0;
    margin-top: 0.25rem;
    display: block;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -0.5rem;
    right: 0.75rem;
    display: flex;
    gap: 0.25rem;
    background: #2f3136;
    border: 1px solid #4a4d52;
    border-radius: 6px;
    padding: 0.25rem;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 5;
}

.message-actions button {
    background: none;
    border: none;
    color: #b9bbbe;
    font-size: 0.78rem;
    cursor: pointer;
    padding: 0.25rem 0.5rem;
    border-radius: 4px;
    white-space: nowrap;
}

.message-actions button:hover {
    background: rgba(255, 255, 255, 0.1);
    color: #fff;
}

@inject IJSRuntime JS

<div class="message-list" @ref="_scrollContainer">
    @if (HasMore)
    {
        <div class="load-more-area">
            @if (IsLoadingMore)
            {
                <span class="loading-text">Loading older messages…</span>
            }
        </div>
    }

    @foreach (var message in Messages)
    {
        <MessageItem Message="message"
                     ThreadReplyCount="GetThreadReplyCount(message.Id)"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />
    }
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
