toolArgs.file_text:
@inject IJSRuntime JS

<div class="message-list" @ref="_scrollContainer">
    @if (HasMore)
    {
        <div class="load-more-area">
            @if (IsLoadingMore)
            {
                <span class="loading-text">Loading older messages…</span>
            }
        </div>
    }

    @foreach (var message in Messages)
    {
        <MessageItem Message="message"
                     ThreadReplyCount="GetThreadReplyCount(message.Id)"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />
    }
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool HasMore { get; set; } = true;
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference _scrollContainer;
    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<MessageList>? _dotNetRef;
    private bool _shouldScrollToBottom = true;

    private int GetThreadReplyCount(int messageId)
        => ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>("import", "./js/chat-scroll.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _jsModule.InvokeVoidAsync("initScrollDetection", _scrollContainer, _dotNetRef);
            await _jsModule.InvokeVoidAsync("scrollToBottom", _scrollContainer);
        }

        if (_shouldScrollToBottom)
        {
            _shouldScrollToBottom = false;
            if (_jsModule is not null)
            {
                await _jsModule.InvokeVoidAsync("scrollToBottom", _scrollContainer);
            }
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (IsLoadingMore || !HasMore) return;

        var previousHeight = _jsModule is not null
            ? await _jsModule.InvokeAsync<double>("getScrollHeight", _scrollContainer)
            : 0;

        await OnLoadMore.InvokeAsync();

        if (_jsModule is not null && previousHeight > 0)
        {
            await Task.Delay(50);
            await _jsModule.InvokeVoidAsync("maintainScrollPosition", _scrollContainer, previousHeight);
        }
    }

    public async Task ScrollToBottomAsync()
    {
        if (_jsModule is not null)
        {
            await _jsModule.InvokeVoidAsync("scrollToBottom", _scrollContainer);
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            await _jsModule.InvokeVoidAsync("removeScrollDetection", _scrollContainer);
            await _jsModule.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

