arguments.file_text:
@page "/chat"
@layout ChatLayout
@inject IChatService ChatService
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        SelectedChannelId="_selectedChannelId"
                        OnChannelSelected="HandleChannelSelected" />
    </div>

    <div class="chat-main @(_isThreadOpen ? "" : "expanded")">
        @if (_selectedChannel is not null)
        {
            <MessageArea @ref="_messageArea"
                         ChannelName="@_selectedChannel.Name"
                         ChannelDescription="@_selectedChannel.Description"
                         Messages="_messages"
                         ThreadReplyCounts="_threadReplyCounts"
                         IsLoadingMore="_isLoadingMore"
                         HasMore="_hasMore"
                         OnLoadMore="HandleLoadMore"
                         OnOpenThread="HandleOpenThread"
                         OnReact="HandleReact"
                         OnSendMessage="HandleSendMessage" />
        }
        else
        {
            <div class="empty-state">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_isThreadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         ThreadMessages="_threadMessages"
                         OnClose="HandleCloseThread"
                         OnSendReply="HandleSendReply" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> _channels = [];
    private int? _selectedChannelId;
    private Channel? _selectedChannel;
    private List<Message> _messages = [];
    private Dictionary<int, int> _threadReplyCounts = new();
    private bool _isLoadingMore;
    private bool _hasMore = true;
    private int _skip;

    private bool _isThreadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadMessages = [];

    private MessageArea? _messageArea;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await HandleChannelSelected(_channels[0].Id);
        }
    }

    private async Task HandleChannelSelected(int channelId)
    {
        if (_selectedChannelId == channelId) return;

        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = [];
        _skip = 0;
        _hasMore = true;
        _threadReplyCounts = new();

        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];

        await LoadMessagesAsync();
        await ChatService.MarkChannelReadAsync(channelId);

        // Update unread count locally
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadMessagesAsync()
    {
        var newMessages = await ChatService.GetMessagesAsync(_selectedChannelId!.Value, _skip, PageSize);
        _hasMore = newMessages.Count == PageSize;

        if (_skip == 0)
        {
            _messages = newMessages;
        }
        else
        {
            _messages = [.. newMessages, .. _messages];
        }

        _skip += newMessages.Count;
        ComputeThreadReplyCounts();
    }

    private async Task HandleLoadMore()
    {
        if (_isLoadingMore || !_hasMore) return;
        _isLoadingMore = true;
        StateHasChanged();

        await LoadMessagesAsync();
        _isLoadingMore = false;
    }

    private async Task HandleOpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        _threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        _isThreadOpen = true;

        // Update thread reply count
        _threadReplyCounts[rootMessageId] = _threadMessages.Count;
    }

    private async Task HandleCloseThread()
    {
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];
        await Task.CompletedTask;
    }

    private async Task HandleSendMessage(string content)
    {
        if (_selectedChannelId is null) return;

        var message = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, null);
        _messages.Add(message);

        if (_messageArea is not null)
        {
            await _messageArea.ScrollToBottomAsync();
        }
    }

    private async Task HandleSendReply(string content)
    {
        if (_selectedChannelId is null || _threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, _threadRootMessage.Id);
        _threadMessages.Add(reply);

        // Update thread reply count
        _threadReplyCounts[_threadRootMessage.Id] = _threadMessages.Count;
    }

    private async Task HandleReact((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);

        // Optimistic update for main messages
        UpdateReactionInList(_messages, reaction.MessageId, reaction.Emoji);
        // Also update thread messages if thread is open
        if (_isThreadOpen)
        {
            UpdateReactionInList(_threadMessages, reaction.MessageId, reaction.Emoji);
            if (_threadRootMessage?.Id == reaction.MessageId)
            {
                _threadRootMessage = UpdateReactionOnMessage(_threadRootMessage, reaction.Emoji);
            }
        }
    }

    private static void UpdateReactionInList(List<Message> messages, int messageId, string emoji)
    {
        var idx = messages.FindIndex(m => m.Id == messageId);
        if (idx >= 0)
        {
            messages[idx] = UpdateReactionOnMessage(messages[idx], emoji);
        }
    }

    private static Message UpdateReactionOnMessage(Message message, string emoji)
    {
        var reactions = message.Reactions.ToList();
        var existing = reactions.FindIndex(r => r.Emoji == emoji);
        if (existing >= 0)
        {
            var reaction = reactions[existing];
            if (!reaction.Users.Contains("You"))
            {
                reactions[existing] = reaction with { Users = [.. reaction.Users, "You"] };
            }
        }
        else
        {
            reactions.Add(new Reaction(emoji, ["You"]));
        }
        return message with { Reactions = reactions };
    }

    private void ComputeThreadReplyCounts()
    {
        var counts = new Dictionary<int, int>();
        foreach (var msg in _messages)
        {
            if (msg.ReplyToId is int parentId)
            {
                counts.TryGetValue(parentId, out var count);
                counts[parentId] = count + 1;
            }
        }
        // Merge with existing counts (from opened threads) — keep the higher value
        foreach (var (id, count) in counts)
        {
            if (!_threadReplyCounts.TryGetValue(id, out var existing) || count > existing)
            {
                _threadReplyCounts[id] = count;
            }
        }
    }

    public ValueTask DisposeAsync()
    {
        return ValueTask.CompletedTask;
    }
}

.chat-container {
    display: flex;
    height: 100vh;
    width: 100vw;
    background: #36393f;
    color: #dcddde;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 300px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.chat-main.expanded {
    /* When no thread panel, main area takes remaining space */
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

.empty-state {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #72767d;
    font-size: 1.1rem;
}

